const rawCall = $('Get Call').first().json;
const call = Array.isArray(rawCall) ? (rawCall[0] || null) : (rawCall || null);
const rawRubric = $('Get Active Rubric').first().json;
const rubricRow = Array.isArray(rawRubric) ? (rawRubric[0] || null) : (rawRubric || null);

if (!call) return [{ json: { __no_findings: true, call_id: null, error: 'Call not found' } }];
if (!rubricRow) return [{ json: { __no_findings: true, call_id: call.id, error: 'No active rubric' } }];

const rules = rubricRow.content;
const callId = call.id;
const callType = call.call_type || 'other';
const findings = [];

const segments = Array.isArray(call.transcript_segments) ? call.transcript_segments : [];

let repLabel = 'host';
if (segments.length > 0) {
  const speakers = [...new Set(segments.map(s => s.speaker).filter(Boolean))];
  if (!speakers.includes('host') && speakers.length > 0) repLabel = speakers[0];
}

const repSegments = segments.filter(s => s.speaker === repLabel);
const repText = repSegments.map(s => s.text || s.content || '').join(' ');

for (const banned of (rules.banned_words || [])) {
  const appliesTo = banned.applies_to_call_types || [];
  if (appliesTo.length > 0 && !appliesTo.includes(callType)) continue;
  const word = banned.word.toLowerCase();
  const regex = new RegExp('\\b' + word + '\\b', 'gi');
  const matches = repText.match(regex) || [];
  if (matches.length > 0) {
    const contextSnippets = repSegments
      .filter(s => (s.text || s.content || '').toLowerCase().includes(word))
      .slice(0, 5)
      .map(s => ({ text: s.text || s.content, timestamp: s.start_time }));
    const suggestion = 'Do not use the word "' + banned.word + '" on ' + appliesTo.join(' or ') + ' calls. ' +
      (banned.reason || 'It removes your authority and expert positioning with the prospect.') +
      ' You said it ' + matches.length + ' time' + (matches.length > 1 ? 's' : '') + ' on this call.';
    findings.push({
      call_id: callId,
      rule_key: 'banned_word_' + word,
      value: { word, count: matches.length, suggestion },
      severity: banned.severity || 'critical',
      context_snippets: contextSnippets
    });
  }
}

for (const filler of (rules.filler_words || [])) {
  const word = filler.word.toLowerCase();
  const regex = new RegExp('\\b' + word + '\\b', 'gi');
  const matches = repText.match(regex) || [];
  const count = matches.length;
  const threshold = filler.threshold_per_call || 5;
  if (count > threshold) {
    const contextSnippets = repSegments
      .filter(s => (s.text || s.content || '').toLowerCase().includes(word))
      .slice(0, 3)
      .map(s => ({ text: s.text || s.content, timestamp: s.start_time }));
    const suggestion = 'Reduce use of the filler word "' + word + '". ' +
      'You said it ' + count + ' times this call (target: under ' + threshold + '). ' +
      'Replace it with a deliberate pause.';
    findings.push({
      call_id: callId,
      rule_key: 'filler_word_' + word,
      value: { word, count, threshold, suggestion },
      severity: filler.severity || 'warning',
      context_snippets: contextSnippets
    });
  }
}

const totalSeconds = call.duration_seconds || 0;
if (rules.talk_ratio && totalSeconds > 0 && segments.length > 0) {
  const repSeconds = repSegments.reduce((sum, s) => {
    const duration = (s.end_time || 0) - (s.start_time || 0);
    return sum + (duration > 0 ? duration : 0);
  }, 0);
  const repPercentage = Math.round((repSeconds / totalSeconds) * 100);
  const maxPercentage = rules.talk_ratio.max_rep_percentage || 60;
  if (repPercentage > maxPercentage) {
    const suggestion = 'You spoke for ' + repPercentage + '% of this call — the target is under ' + maxPercentage + '%. Ask a question, then stop talking.';
    findings.push({
      call_id: callId,
      rule_key: 'talk_ratio',
      value: { rep_percentage: repPercentage, max_allowed: maxPercentage, rep_seconds: Math.round(repSeconds), total_seconds: totalSeconds, suggestion },
      severity: rules.talk_ratio.severity || 'warning',
      context_snippets: []
    });
  }
}

if (findings.length === 0) return [{ json: { __no_findings: true, call_id: callId } }];
return findings.map(f => ({ json: f }));

const findings = $input.all().map(item => ({
  call_id: item.json.call_id,
  rule_key: item.json.rule_key,
  value: item.json.value,
  severity: item.json.severity,
  context_snippets: item.json.context_snippets || []
}));
return [{ json: { findings } }];
